import{c as a,a7 as t,y as n,B as o}from"./chunks/framework.3cjvm90C.js";const p=JSON.parse('{"title":"SGLang 官方超参数调优指南","description":"基于运行日志关键指标，指导如何调整 SGLang 核心超参数以最大化离线批处理推理吞吐量。","frontmatter":{"title":"SGLang 官方超参数调优指南","description":"基于运行日志关键指标，指导如何调整 SGLang 核心超参数以最大化离线批处理推理吞吐量。"},"headers":[],"relativePath":"inference/sglang/sglang_tuning.md","filePath":"inference/sglang/sglang_tuning.md","lastUpdated":1782447613000}'),s={name:"inference/sglang/sglang_tuning.md"};function i(r,e,d,l,c,g){return t(),n("div",null,[...e[0]||(e[0]=[o('<h1 id="🚀-sglang-官方超参数调优指南" tabindex="-1">🚀 SGLang 官方超参数调优指南 <a class="header-anchor" href="#🚀-sglang-官方超参数调优指南" aria-label="Permalink to “🚀 SGLang 官方超参数调优指南”">​</a></h1><p>在大语言模型（LLM）的离线批处理推理场景中，追求极限的<strong>吞吐量（Throughput）</strong>是性能优化的核心目标。实现高吞吐量的最关键因素在于获得并维持一个巨大的<strong>有效批处理大小（Effective Batch Size）</strong>。</p><p>SGLang 提供了精细的参数配置，让开发者能够根据自身硬件和工作负载特性进行深度优化。本指南将基于 SGLang 运行日志中的关键指标，详细阐述如何通过调整核心超参数来最大化离线推理性能。</p><h2 id="一、关键性能指标监控" tabindex="-1">一、关键性能指标监控 <a class="header-anchor" href="#一、关键性能指标监控" aria-label="Permalink to “一、关键性能指标监控”">​</a></h2><p>当 SGLang 服务在高负载下稳定运行时，您应密切关注服务器日志中类似以下的指标输出：</p><div class="language-bash line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Decode</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> batch.</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> #running-req: 233, #token: 370959, token usage: 0.82, cuda graph: True, gen throughput (token/s): 4594.01, #queue-req: 317</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>其中，两个关键指标是：</p><ol><li><strong><code>#queue-req</code> (队列请求数)：</strong> 表示当前在调度队列中等待处理的请求数量。</li><li><strong><code>token usage</code> (KV 缓存 Token 利用率)：</strong> 表示服务器 KV 缓存内存的实际利用率，0.0～1.0 之间的小数，1.0 表示占满。</li></ol><p>此外：</p><ul><li><p><code>#running-req</code>：正在调度执行的请求数。</p></li><li><p><code>#token</code>：当前 batch 生成的总 token 数。</p></li><li><p><code>cuda graph</code>：是否开启 CUDA 计算图。</p></li><li><p><code>gen throughput (token/s)</code>：SGLang 平均每秒处理的 Token 数。</p></li></ul><h2 id="二、请求负载与队列管理-queue-req" tabindex="-1">二、请求负载与队列管理 (<code>#queue-req</code>) <a class="header-anchor" href="#二、请求负载与队列管理-queue-req" aria-label="Permalink to “二、请求负载与队列管理 (#queue-req)”">​</a></h2><p><code>#queue-req</code> 能够反映客户端提交请求的速度是否匹配得上服务器的处理能力。</p><h3 id="调优-queue-req" tabindex="-1">调优 <code>#queue-req</code> <a class="header-anchor" href="#调优-queue-req" aria-label="Permalink to “调优 #queue-req”">​</a></h3><p>如果日志中频繁出现 <strong><code>#queue-req: 0</code></strong>，说明您的客户端请求提交速度过慢，服务器处于饥饿状态，无法满载运行，可适当增加请求的数量。</p><ul><li><strong>理想范围：</strong> 保持在一个适度的范围内，例如 <strong>$100 \\sim 2000$</strong>。</li><li><strong>避免过大：</strong> <code>#queue-req</code> 过大会显著增加服务器调度（Scheduling）的开销，影响效率。</li></ul><h2 id="三、kv-缓存-token-利用率调优-token-usage" tabindex="-1">三、KV 缓存 Token 利用率调优 (<code>token usage</code>) <a class="header-anchor" href="#三、kv-缓存-token-利用率调优-token-usage" aria-label="Permalink to “三、KV 缓存 Token 利用率调优 (token usage)”">​</a></h2><p>Token 利用率直接反映了 GPU 内存资源的使用效率。我们的目标是实现高利用率，即 <strong><code>token usage &gt; 0.9</code></strong>。</p><h3 id="_1-利用率过低-token-浪费" tabindex="-1">1. 利用率过低（Token 浪费） <a class="header-anchor" href="#_1-利用率过低-token-浪费" aria-label="Permalink to “1. 利用率过低（Token 浪费）”">​</a></h3><p>如果频繁看到 <strong><code>token usage &lt; 0.9</code></strong>，同时 <strong><code>#queue-req &gt; 0</code></strong>，这通常意味着服务器在接受新请求时过于<strong>保守</strong>。</p><ul><li><strong>原因分析：</strong> 这种情况常见于用户请求设置了很大的 <code>max_new_tokens</code>，但由于遇到 EOS 或停止字符串而提前结束，导致系统预留了过多的 KV 缓存空间。</li><li><strong>调优方法：</strong> 尝试降低 <strong><code>--schedule-conservativeness</code></strong> 的值，例如设置为 <code>0.3</code>。</li></ul><h3 id="_2-利用率过高-内存紧张" tabindex="-1">2. 利用率过高（内存紧张） <a class="header-anchor" href="#_2-利用率过高-内存紧张" aria-label="Permalink to “2. 利用率过高（内存紧张）”">​</a></h3><p>如果您观察到 <strong><code>token usage</code> 极高</strong>，并频繁出现以下警告：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>KV cache pool is full. Retract requests. ...</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>这表明 KV 缓存池已满，服务器正在收回请求。</p><ul><li><strong>调优方法：</strong> 此时应提高 <strong><code>--schedule-conservativeness</code></strong> 的值，例如设置为 <code>1.3</code>，以更保守地接受新请求，避免过度占用缓存。</li><li><strong>容忍范围：</strong> 如果此类警告偶尔出现（例如每分钟 1 次），则是可以接受的正常现象。</li></ul><h2 id="四、内存分配与-kv-缓存池容量优化-mem-fraction-static" tabindex="-1">四、内存分配与 KV 缓存池容量优化 (<code>--mem-fraction-static</code>) <a class="header-anchor" href="#四、内存分配与-kv-缓存池容量优化-mem-fraction-static" aria-label="Permalink to “四、内存分配与 KV 缓存池容量优化 (--mem-fraction-static)”">​</a></h2><p>SGLang 的总内存使用包含以下几个主要部分： $$ \\text{总显存} = \\text{模型权重} + \\text{KV 缓存池} + \\text{CUDA 图缓冲区} + \\text{激活值} $$ 参数 <code>--mem-fraction-static</code> 决定了前两项占总 GPU 显存的比例： $$ \\text{mem_fraction_static} = \\frac{\\text{模型权重} + \\text{KV 缓存池} }{\\text{GPU 显存容量} } $$ 为了支持更高的并发（即更大的 KV 缓存池），应尽可能提高 <code>--mem-fraction-static</code>，同时还要为激活和 CUDA 图缓冲区保留足够的内存。</p><h3 id="调优步骤" tabindex="-1">调优步骤 <a class="header-anchor" href="#调优步骤" aria-label="Permalink to “调优步骤”">​</a></h3><ol><li><p><strong>确定激活值所需空间：</strong> 经验法则是为激活值（Activations）预留 $5 \\sim 8\\text{ GB}$ 的显存。</p></li><li><p><strong>检查日志：</strong> 在服务器启动日志中查找 <code>available_gpu_mem</code> 的值：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>[2025-08-11 17:17:03] ..., available_gpu_mem=13.50 GB</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></li><li><p><strong>调整策略：</strong></p><ul><li>如果 <code>available_gpu_mem</code> 很高（如 $10\\text{ GB}$ 以上），说明 KV 缓存池分配不足，应<strong>增加</strong> <code>--mem-fraction-static</code>。</li><li>如果 <code>available_gpu_mem</code> 过低，请<strong>降低</strong> <code>--mem-fraction-static</code>，以防后续的内存溢出（OOM）。</li></ul></li></ol><p>最直接的方法是每次以 $0.01$ 的增量提高 <code>--mem-fraction-static</code>，直到您的工作负载开始出现 OOM 错误。</p><h2 id="五、内存溢出-oom-的避免与解决" tabindex="-1">五、内存溢出（OOM）的避免与解决 <a class="header-anchor" href="#五、内存溢出-oom-的避免与解决" aria-label="Permalink to “五、内存溢出（OOM）的避免与解决”">​</a></h2><p>当遇到内存溢出（OOM）错误时，应根据 OOM 发生的阶段进行针对性调整：</p><table tabindex="0"><thead><tr><th><strong>OOM 发生阶段</strong></th><th><strong>调优参数</strong></th><th><strong>调整方向</strong></th><th><strong>影响</strong></th></tr></thead><tbody><tr><td><strong>预填充 (Prefill)</strong></td><td><code>--chunked-prefill-size</code></td><td>降低至 <code>4096</code> 或 <code>2048</code></td><td>节省内存，但会降低长提示的预填充速度。</td></tr><tr><td><strong>解码 (Decoding)</strong></td><td><code>--max-running-requests</code></td><td>降低</td><td>限制了最大并发数。</td></tr><tr><td><strong>通用 OOM</strong></td><td><code>--mem-fraction-static</code></td><td>降低至 <code>0.8</code> 或 <code>0.7</code></td><td>减少 KV 缓存池大小，限制了峰值吞吐量和并发。</td></tr></tbody></table><h2 id="六、高级加速机制与并行策略" tabindex="-1">六、高级加速机制与并行策略 <a class="header-anchor" href="#六、高级加速机制与并行策略" aria-label="Permalink to “六、高级加速机制与并行策略”">​</a></h2><h3 id="_1-cuda-graph-优化-cuda-graph-max-bs" tabindex="-1">1. CUDA Graph 优化 (<code>--cuda-graph-max-bs</code>) <a class="header-anchor" href="#_1-cuda-graph-优化-cuda-graph-max-bs" aria-label="Permalink to “1. CUDA Graph 优化 (--cuda-graph-max-bs)”">​</a></h3><p>CUDA Graph 默认仅对小批处理（例如小于 $160$ 或 $256$）启用。对于某些模型和大规模张量并行（TP），扩大 CUDA Graph 的适用范围能带来性能提升。</p><ul><li><strong>调优方法：</strong> 尝试将 <code>--cuda-graph-max-bs</code> 增加到一个更大的值（如 $512$ 或 $768$）。</li><li><strong>注意事项：</strong> CUDA Graph 会占用额外的内存，因此可能需要同时降低 <code>--mem-fraction-static</code>。</li></ul><h3 id="_2-数据并行与张量并行-dp-size-tp-size" tabindex="-1">2. 数据并行与张量并行 (<code>--dp-size</code>, <code>--tp-size</code>) <a class="header-anchor" href="#_2-数据并行与张量并行-dp-size-tp-size" aria-label="Permalink to “2. 数据并行与张量并行 (--dp-size, --tp-size)”">​</a></h3><p>在 GPU 内存充足的情况下，<strong>数据并行（DP）</strong>通常比张量并行（TP）能带来更高的吞吐量。</p><ul><li><strong>优先级：</strong> 总是优先考虑使用数据并行来提高吞吐量。</li><li><strong>建议：</strong> 参考 SGLang Router 的文档，它提供了更优化的数据并行方案。</li></ul><h3 id="_3-其他优化选项" tabindex="-1">3. 其他优化选项 <a class="header-anchor" href="#_3-其他优化选项" aria-label="Permalink to “3. 其他优化选项”">​</a></h3><ul><li><strong><code>--enable-torch-compile</code>：</strong> 对小模型和小批处理加速有效。</li><li><strong>量化：</strong> 尝试不同的量化方法，例如使用 <code>--quantization fp8</code> 进行 FP8 量化。</li><li><strong>调度策略：</strong> 如果工作负载中存在大量共享前缀，可以尝试使用 <code>--schedule-policy lpm</code>（最长前缀匹配）。该策略通过重新排序请求来提高缓存命中率，但会引入额外的调度开销。</li></ul>',42)])])}const u=a(s,[["render",i]]);export{p as __pageData,u as default};
